import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { openMT5Buy, openMT5Sell, closeAllMT5Positions } from '../services/api';
import './TradingPanel.css';

function TradingPanel({ currentTick, accountInfo, onTradeSuccess }) {
  const { t } = useTranslation();
  const [volume, setVolume] = useState(0.01);
  const [sl, setSl] = useState('');
  const [tp, setTp] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleBuy = async () => {
    setIsLoading(true);
    try {
      await openMT5Buy(
        volume,
        sl ? parseFloat(sl) : null,
        tp ? parseFloat(tp) : null
      );
      onTradeSuccess && onTradeSuccess();
    } catch (error) {
      console.error('Failed to open buy position:', error);
      alert('Failed to open buy position: ' + (error.response?.data?.detail || error.message));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSell = async () => {
    setIsLoading(true);
    try {
      await openMT5Sell(
        volume,
        sl ? parseFloat(sl) : null,
        tp ? parseFloat(tp) : null
      );
      onTradeSuccess && onTradeSuccess();
    } catch (error) {
      console.error('Failed to open sell position:', error);
      alert('Failed to open sell position: ' + (error.response?.data?.detail || error.message));
    } finally {
      setIsLoading(false);
    }
  };

  const handleCloseAll = async () => {
    setIsLoading(true);
    try {
      await closeAllMT5Positions();
      onTradeSuccess && onTradeSuccess();
    } catch (error) {
      console.error('Failed to close all positions:', error);
      alert('Failed to close all positions: ' + (error.response?.data?.detail || error.message));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="trading-panel">
      <h3>{t('goldChart.tradingPanel.title')}</h3>
      
      {currentTick && (
        <div className="price-display">
          <div className="price-item">
            <span className="price-label">{t('goldChart.tradingPanel.bid')}</span>
            <span className="price-value bid">{currentTick.bid?.toFixed(2)}</span>
          </div>
          <div className="price-item">
            <span className="price-label">{t('goldChart.tradingPanel.ask')}</span>
            <span className="price-value ask">{currentTick.ask?.toFixed(2)}</span>
          </div>
          <div className="price-item">
            <span className="price-label">{t('goldChart.tradingPanel.spread')}</span>
            <span className="price-value spread">{((currentTick.ask || 0) - (currentTick.bid || 0)).toFixed(2)}</span>
          </div>
        </div>
      )}

      {accountInfo && (
        <div className="account-display">
          <div className="account-item">
            <span className="account-label">{t('goldChart.tradingPanel.balance')}</span>
            <span className="account-value">${accountInfo.balance?.toFixed(2)}</span>
          </div>
          <div className="account-item">
            <span className="account-label">{t('goldChart.tradingPanel.equity')}</span>
            <span className="account-value">${accountInfo.equity?.toFixed(2)}</span>
          </div>
        </div>
      )}

      <div className="trading-form">
        <div className="form-group">
          <label>{t('goldChart.tradingPanel.lotSize')}</label>
          <input
            type="number"
            step="0.01"
            min="0.01"
            value={volume}
            onChange={(e) => setVolume(parseFloat(e.target.value))}
          />
        </div>
        <div className="form-group">
          <label>{t('goldChart.tradingPanel.stopLoss')}</label>
          <input
            type="number"
            step="0.01"
            placeholder="Optional"
            value={sl}
            onChange={(e) => setSl(e.target.value)}
          />
        </div>
        <div className="form-group">
          <label>{t('goldChart.tradingPanel.takeProfit')}</label>
          <input
            type="number"
            step="0.01"
            placeholder="Optional"
            value={tp}
            onChange={(e) => setTp(e.target.value)}
          />
        </div>
        <div className="button-group">
          <button 
            className="btn-buy" 
            onClick={handleBuy} 
            disabled={isLoading}
          >
            {t('goldChart.tradingPanel.buy')}
          </button>
          <button 
            className="btn-sell" 
            onClick={handleSell} 
            disabled={isLoading}
          >
            {t('goldChart.tradingPanel.sell')}
          </button>
        </div>
        <button 
          className="btn-close-all" 
          onClick={handleCloseAll} 
          disabled={isLoading}
        >
          {t('goldChart.tradingPanel.closeAll')}
        </button>
      </div>
    </div>
  );
}

export default TradingPanel;
